import{_ as s,o as a,c as n,a4 as e}from"./chunks/framework._in6GHBg.js";const h=JSON.parse('{"title":"能量动量详解","description":"","frontmatter":{},"headers":[],"relativePath":"physics/energy.md","filePath":"physics/energy.md"}'),l={name:"physics/energy.md"};function p(i,t,r,d,o,c){return a(),n("div",null,[...t[0]||(t[0]=[e(`<h1 id="能量动量详解" tabindex="-1">能量动量详解 <a class="header-anchor" href="#能量动量详解" aria-label="Permalink to &quot;能量动量详解&quot;">​</a></h1><p><strong>类别五：能量与动量</strong><br><strong>学习时机</strong>：高一下学期 4-7月<br><strong>核心能力</strong>：功和能的关系、动量守恒应用、综合问题分析</p><hr><h2 id="类别概述" tabindex="-1">类别概述 <a class="header-anchor" href="#类别概述" aria-label="Permalink to &quot;类别概述&quot;">​</a></h2><p>能量和动量是高中物理的两大核心工具，它们提供了分析力学问题的两种视角：</p><ul><li><strong>能量视角</strong>：关注过程的始末，不关注中间细节（标量，只有大小）</li><li><strong>动量视角</strong>：关注相互作用前后的状态，适用于碰撞、爆炸（矢量，有方向）</li></ul><p><strong>五个模型的递进关系</strong>：</p><ul><li><strong>模型16 动能定理</strong>：处理单个物体的能量变化</li><li><strong>模型17 机械能守恒</strong>：处理只有重力/弹力做功的系统</li><li><strong>模型18 功能关系</strong>：处理有摩擦力等非保守力的情况</li><li><strong>模型19 动量守恒</strong>：处理碰撞、爆炸等相互作用</li><li><strong>模型20 能量动量综合</strong>：处理复杂多过程问题</li></ul><p><strong>核心思想</strong>：</p><ul><li>能量守恒（广义）：能量不会消失，只会转化</li><li>动量守恒：系统不受外力或外力合力为零时，总动量守恒</li></ul><hr><h2 id="模型16-动能定理" tabindex="-1">模型16：动能定理 <a class="header-anchor" href="#模型16-动能定理" aria-label="Permalink to &quot;模型16：动能定理&quot;">​</a></h2><h3 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h3><p><strong>功的定义</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>W = F·s·cosθ</span></span>
<span class="line"><span></span></span>
<span class="line"><span>θ = 0°：力与位移同向，做正功</span></span>
<span class="line"><span>θ = 90°：力与位移垂直，不做功</span></span>
<span class="line"><span>θ = 180°：力与位移反向，做负功</span></span></code></pre></div><p><strong>动能</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Ek = ½mv²</span></span></code></pre></div><p><strong>动能定理</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>W合 = ΔEk = Ek末 - Ek初 = ½mv₂² - ½mv₁²</span></span></code></pre></div><p><strong>关键理解</strong>：</p><ul><li>动能定理是标量方程，无方向</li><li>适用于直线运动和曲线运动</li><li>适用于恒力做功和变力做功（变力用功的定义积分）</li><li><strong>只看初末状态，不看中间过程</strong>（优势！）</li></ul><h3 id="典型应用" tabindex="-1">典型应用 <a class="header-anchor" href="#典型应用" aria-label="Permalink to &quot;典型应用&quot;">​</a></h3><p><strong>应用1：求变力做功</strong></p><p>若力是变力或路径复杂，直接用W=Fs困难，可用动能定理间接求。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>W合 = ΔEk</span></span>
<span class="line"><span>W其他已知力 + W待求 = ΔEk</span></span>
<span class="line"><span>→ 可求出待求力的功</span></span></code></pre></div><p><strong>应用2：曲线运动求速度</strong></p><p>如平抛运动、圆周运动，用牛顿第二定律求加速度再积分复杂，用动能定理简单。</p><p><strong>例题</strong>：小球从高度h处静止滑下光滑曲面，求最低点的速度。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>只有重力做功：</span></span>
<span class="line"><span>W合 = mgh = ΔEk = ½mv² - 0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>v = √(2gh)</span></span></code></pre></div><h3 id="常见力做功特点" tabindex="-1">常见力做功特点 <a class="header-anchor" href="#常见力做功特点" aria-label="Permalink to &quot;常见力做功特点&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">力</th><th style="text-align:left;">做功公式</th><th style="text-align:left;">特点</th></tr></thead><tbody><tr><td style="text-align:center;">重力</td><td style="text-align:left;">WG = mgh</td><td style="text-align:left;">只看高度差，与路径无关</td></tr><tr><td style="text-align:center;">弹力</td><td style="text-align:left;">W弹 = ½kx₁² - ½kx₂²</td><td style="text-align:left;">弹性势能变化量的负值</td></tr><tr><td style="text-align:center;">摩擦力</td><td style="text-align:left;">Wf = -f·s路程</td><td style="text-align:left;">与路径有关，生热Q = f·s相对</td></tr><tr><td style="text-align:center;">万有引力</td><td style="text-align:left;">W引 = GMm(1/r₂ - 1/r₁)</td><td style="text-align:left;">与路径无关</td></tr><tr><td style="text-align:center;">电场力</td><td style="text-align:left;">W电 = qU = qEd</td><td style="text-align:left;">与路径无关</td></tr></tbody></table><hr><h2 id="模型17-机械能守恒" tabindex="-1">模型17：机械能守恒 <a class="header-anchor" href="#模型17-机械能守恒" aria-label="Permalink to &quot;模型17：机械能守恒&quot;">​</a></h2><h3 id="核心概念-1" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念-1" aria-label="Permalink to &quot;核心概念&quot;">​</a></h3><p><strong>机械能</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>E = Ek + Ep</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ek = ½mv²（动能）</span></span>
<span class="line"><span>Ep重力 = mgh（重力势能）</span></span>
<span class="line"><span>Ep弹性 = ½kx²（弹性势能）</span></span></code></pre></div><p><strong>机械能守恒条件</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>只有重力或弹力做功，其他力不做功或做功代数和为零</span></span>
<span class="line"><span></span></span>
<span class="line"><span>ΔE = 0 → Ek₁ + Ep₁ = Ek₂ + Ep₂</span></span></code></pre></div><p><strong>判断方法</strong>：</p><ol><li>看是否有摩擦力（有摩擦→不守恒，转化为内能）</li><li>看是否有外力做功（如人推、发动机牵引）</li><li>看是否有爆炸、碰撞（一般机械能不守恒）</li></ol><h3 id="典型应用-1" tabindex="-1">典型应用 <a class="header-anchor" href="#典型应用-1" aria-label="Permalink to &quot;典型应用&quot;">​</a></h3><p><strong>应用：抛体运动、单摆、弹簧振子</strong></p><p><strong>例题</strong>：小球从A点静止释放，沿光滑圆弧轨道滑到B点，求B点速度。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>光滑→无摩擦，只有重力做功→机械能守恒</span></span>
<span class="line"><span></span></span>
<span class="line"><span>设A点为势能零点：</span></span>
<span class="line"><span>EkA + EpA = EkB + EpB</span></span>
<span class="line"><span>0 + mgR = ½mv² + 0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>v = √(2gR)</span></span></code></pre></div><h3 id="机械能守恒-vs-动能定理" tabindex="-1">机械能守恒 vs 动能定理 <a class="header-anchor" href="#机械能守恒-vs-动能定理" aria-label="Permalink to &quot;机械能守恒 vs 动能定理&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">对比</th><th style="text-align:center;">机械能守恒</th><th style="text-align:center;">动能定理</th></tr></thead><tbody><tr><td style="text-align:center;">研究对象</td><td style="text-align:center;">系统（物体+地球+弹簧）</td><td style="text-align:center;">单个物体</td></tr><tr><td style="text-align:center;">方程形式</td><td style="text-align:center;">Ek₁+Ep₁ = Ek₂+Ep₂</td><td style="text-align:center;">W合 = ΔEk</td></tr><tr><td style="text-align:center;">适用条件</td><td style="text-align:center;">只有重力/弹力做功</td><td style="text-align:center;">任何情况</td></tr><tr><td style="text-align:center;">优势</td><td style="text-align:center;">不涉及力的细节</td><td style="text-align:center;">可求功和能的定量关系</td></tr></tbody></table><p><strong>建议</strong>：能用机械能守恒时先用（简单），不能用时用动能定理（通用）。</p><hr><h2 id="模型18-功能关系" tabindex="-1">模型18：功能关系 <a class="header-anchor" href="#模型18-功能关系" aria-label="Permalink to &quot;模型18：功能关系&quot;">​</a></h2><h3 id="核心概念-2" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念-2" aria-label="Permalink to &quot;核心概念&quot;">​</a></h3><p><strong>功能关系本质是能量守恒的另一种表述</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>功是能量转化的量度</span></span></code></pre></div><p><strong>常见功能关系</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">做功的力</th><th style="text-align:center;">能量转化</th><th style="text-align:left;">功的计算</th></tr></thead><tbody><tr><td style="text-align:center;">重力</td><td style="text-align:center;">重力势能↔动能</td><td style="text-align:left;">WG = -ΔEp重 = mgh</td></tr><tr><td style="text-align:center;">弹力</td><td style="text-align:center;">弹性势能↔动能</td><td style="text-align:left;">W弹 = -ΔEp弹</td></tr><tr><td style="text-align:center;">摩擦力</td><td style="text-align:center;">机械能→内能</td><td style="text-align:left;">Wf = -Q = -f·s相对</td></tr><tr><td style="text-align:center;">电场力</td><td style="text-align:center;">电势能↔动能</td><td style="text-align:left;">W电 = -ΔEp电</td></tr><tr><td style="text-align:center;">合力</td><td style="text-align:center;">动能变化</td><td style="text-align:left;">W合 = ΔEk</td></tr><tr><td style="text-align:center;">非保守力</td><td style="text-align:center;">机械能变化</td><td style="text-align:left;">W非保守 = ΔE机</td></tr></tbody></table><p><strong>核心公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>W合 = ΔEk（动能定理）</span></span>
<span class="line"><span>W非保守力 = ΔE机（功能原理）</span></span>
<span class="line"><span>W摩擦力 = -Q（热量）</span></span></code></pre></div><h3 id="典型应用-板块模型热量计算" tabindex="-1">典型应用：板块模型热量计算 <a class="header-anchor" href="#典型应用-板块模型热量计算" aria-label="Permalink to &quot;典型应用：板块模型热量计算&quot;">​</a></h3><p><strong>问题</strong>：质量为m的物块以v₀滑上静止木板M，最终共速，求产生的热量。</p><p><strong>解析</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>能量守恒：系统动能损失 = 热量</span></span>
<span class="line"><span>Q = ½mv₀² - ½(m+M)v共²</span></span>
<span class="line"><span></span></span>
<span class="line"><span>或用摩擦力做功：</span></span>
<span class="line"><span>Q = f·s相对</span></span>
<span class="line"><span></span></span>
<span class="line"><span>两种方法等价</span></span></code></pre></div><h3 id="能量守恒方程写法" tabindex="-1">能量守恒方程写法 <a class="header-anchor" href="#能量守恒方程写法" aria-label="Permalink to &quot;能量守恒方程写法&quot;">​</a></h3><p><strong>通用写法</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>E初 = E末 + E损失</span></span>
<span class="line"><span></span></span>
<span class="line"><span>或：</span></span>
<span class="line"><span>减少的能量 = 增加的能量</span></span></code></pre></div><p><strong>例题</strong>：物块从高h处滑下，经过粗糙水平面（摩擦系数μ，长度L），求最终停止位置。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>能量守恒：</span></span>
<span class="line"><span>重力势能减少 = 摩擦力做功（生热）</span></span>
<span class="line"><span>mgh = μmgL</span></span>
<span class="line"><span></span></span>
<span class="line"><span>解得：L = h/μ</span></span></code></pre></div><hr><h2 id="模型19-动量守恒" tabindex="-1">模型19：动量守恒 <a class="header-anchor" href="#模型19-动量守恒" aria-label="Permalink to &quot;模型19：动量守恒&quot;">​</a></h2><h3 id="核心概念-3" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念-3" aria-label="Permalink to &quot;核心概念&quot;">​</a></h3><p><strong>动量</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>p = mv（矢量，方向与速度相同）</span></span></code></pre></div><p><strong>冲量</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I = F·t = Δp（矢量）</span></span></code></pre></div><p><strong>动量守恒定律</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>系统不受外力或外力合力为零时，总动量守恒</span></span>
<span class="line"><span></span></span>
<span class="line"><span>m₁v₁ + m₂v₂ = m₁v₁&#39; + m₂v₂&#39;</span></span></code></pre></div><p><strong>适用条件</strong>：</p><ol><li>系统不受外力（理想情况）</li><li>外力合力为零（如水平方向动量守恒）</li><li>内力远大于外力（短暂过程，如碰撞、爆炸）</li></ol><h3 id="碰撞类型" tabindex="-1">碰撞类型 <a class="header-anchor" href="#碰撞类型" aria-label="Permalink to &quot;碰撞类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">碰撞类型</th><th style="text-align:center;">特点</th><th style="text-align:left;">方程</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>弹性碰撞</strong></td><td style="text-align:center;">动能守恒</td><td style="text-align:left;">动量守恒 + 动能守恒</td></tr><tr><td style="text-align:center;"><strong>非弹性碰撞</strong></td><td style="text-align:center;">动能不守恒</td><td style="text-align:left;">只有动量守恒</td></tr><tr><td style="text-align:center;"><strong>完全非弹性碰撞</strong></td><td style="text-align:center;">共速，动能损失最大</td><td style="text-align:left;">动量守恒 + v₁&#39;=v₂&#39;</td></tr></tbody></table><p><strong>弹性碰撞公式</strong>（记住结论）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>v₁&#39; = [(m₁-m₂)v₁ + 2m₂v₂]/(m₁+m₂)</span></span>
<span class="line"><span>v₂&#39; = [(m₂-m₁)v₂ + 2m₁v₁]/(m₁+m₂)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>特殊情况：v₂=0（静止目标）</span></span>
<span class="line"><span>v₁&#39; = (m₁-m₂)v₁/(m₁+m₂)</span></span>
<span class="line"><span>v₂&#39; = 2m₁v₁/(m₁+m₂)</span></span></code></pre></div><p><strong>记忆口诀</strong>：</p><ul><li>等质量交换速度：m₁=m₂时，v₁&#39;=0，v₂&#39;=v₁</li><li>大撞小，同向走；小撞大，反弹回</li></ul><h3 id="典型应用-2" tabindex="-1">典型应用 <a class="header-anchor" href="#典型应用-2" aria-label="Permalink to &quot;典型应用&quot;">​</a></h3><p><strong>应用1：人船模型</strong></p><p><strong>问题</strong>：质量为m的人从质量为M、长为L的船的一端走到另一端，求船的位移。</p><p><strong>解析</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>水平方向动量守恒（系统不受外力）：</span></span>
<span class="line"><span>设人速度v（向右），船速度V（向左）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>mv = MV（动量大小相等，方向相反）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>两边乘时间t：</span></span>
<span class="line"><span>m·x人 = M·x船</span></span>
<span class="line"><span></span></span>
<span class="line"><span>且 x人 + x船 = L</span></span>
<span class="line"><span></span></span>
<span class="line"><span>解得：</span></span>
<span class="line"><span>x船 = mL/(m+M)（向左）</span></span>
<span class="line"><span>x人 = ML/(m+M)（向右）</span></span></code></pre></div><p><strong>结论</strong>：位移与质量成反比</p><p><strong>应用2：反冲运动</strong></p><p><strong>问题</strong>：总质量为M的火箭（含燃料）静止，喷出质量为m的气体，气体速度为v（相对地面），求火箭速度。</p><p><strong>解析</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>动量守恒（初态总动量为0）：</span></span>
<span class="line"><span>0 = mv + (M-m)V</span></span>
<span class="line"><span></span></span>
<span class="line"><span>V = -mv/(M-m)（负号表示与气体反向）</span></span></code></pre></div><hr><h2 id="模型20-能量动量综合" tabindex="-1">模型20：能量动量综合 <a class="header-anchor" href="#模型20-能量动量综合" aria-label="Permalink to &quot;模型20：能量动量综合&quot;">​</a></h2><h3 id="核心思想" tabindex="-1">核心思想 <a class="header-anchor" href="#核心思想" aria-label="Permalink to &quot;核心思想&quot;">​</a></h3><p><strong>复杂问题的分析框架</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 分段分析：按时间或空间分成若干段</span></span>
<span class="line"><span>2. 每段选择合适工具：</span></span>
<span class="line"><span>   - 涉及时间t和力F → 用动量定理（Ft = Δp）</span></span>
<span class="line"><span>   - 涉及位移s和力F → 用动能定理（Fs = ΔEk）</span></span>
<span class="line"><span>   - 碰撞、爆炸 → 用动量守恒</span></span>
<span class="line"><span>   - 只有重力做功 → 用机械能守恒</span></span>
<span class="line"><span>3. 找衔接点：前段末态 = 后段初态</span></span></code></pre></div><h3 id="典型综合问题" tabindex="-1">典型综合问题 <a class="header-anchor" href="#典型综合问题" aria-label="Permalink to &quot;典型综合问题&quot;">​</a></h3><p><strong>问题类型1：碰撞+滑动</strong></p><p><strong>例题</strong>：物块A（质量m₁，速度v₀）与静止物块B（质量m₂）弹性碰撞后，B滑上静止木板C（质量m₃），求最终三者速度。</p><p><strong>解析</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>阶段1：A与B弹性碰撞</span></span>
<span class="line"><span>动量守恒：m₁v₀ = m₁v₁ + m₂v₂</span></span>
<span class="line"><span>动能守恒：½m₁v₀² = ½m₁v₁² + ½m₂v₂²</span></span>
<span class="line"><span>→ 解得v₁、v₂</span></span>
<span class="line"><span></span></span>
<span class="line"><span>阶段2：B在C上滑动</span></span>
<span class="line"><span>水平动量守恒：m₂v₂ = (m₂+m₃)v共</span></span>
<span class="line"><span>能量损失：Q = ½m₂v₂² - ½(m₂+m₃)v共² = f·s相对</span></span>
<span class="line"><span>→ 解得v共、滑行距离</span></span></code></pre></div><p><strong>问题类型2：弹簧+碰撞</strong></p><p><strong>例题</strong>：物块A以v₀撞向连有弹簧的物块B，求弹簧最大压缩量。</p><p><strong>解析</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>关键点：弹簧最大压缩时，A和B速度相同（相对速度为0）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>动量守恒：m₁v₀ = (m₁+m₂)v共</span></span>
<span class="line"><span>→ v共 = m₁v₀/(m₁+m₂)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>能量守恒：</span></span>
<span class="line"><span>½m₁v₀² = ½(m₁+m₂)v共² + Ep弹max</span></span>
<span class="line"><span>→ Ep弹max = ½m₁v₀² - ½(m₁+m₂)[m₁v₀/(m₁+m₂)]²</span></span>
<span class="line"><span>         = ½·m₁m₂v₀²/(m₁+m₂)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>最大压缩量由Ep弹max = ½kx²求得</span></span></code></pre></div><h3 id="解题策略总结" tabindex="-1">解题策略总结 <a class="header-anchor" href="#解题策略总结" aria-label="Permalink to &quot;解题策略总结&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">问题特征</th><th style="text-align:center;">首选工具</th><th style="text-align:center;">次选工具</th></tr></thead><tbody><tr><td style="text-align:center;">碰撞过程</td><td style="text-align:center;">动量守恒</td><td style="text-align:center;">动能守恒（弹性）</td></tr><tr><td style="text-align:center;">涉及时间</td><td style="text-align:center;">动量定理</td><td style="text-align:center;">牛顿定律</td></tr><tr><td style="text-align:center;">涉及位移</td><td style="text-align:center;">动能定理</td><td style="text-align:center;">能量守恒</td></tr><tr><td style="text-align:center;">往复运动</td><td style="text-align:center;">能量守恒</td><td style="text-align:center;">动量定理（分次）</td></tr><tr><td style="text-align:center;">多物体系统</td><td style="text-align:center;">动量守恒+能量守恒</td><td style="text-align:center;">隔离法+动能定理</td></tr></tbody></table><hr><h2 id="类别总结" tabindex="-1">类别总结 <a class="header-anchor" href="#类别总结" aria-label="Permalink to &quot;类别总结&quot;">​</a></h2><p><strong>能量vs动量选择指南</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">情境</th><th style="text-align:center;">用能量</th><th style="text-align:center;">用动量</th><th style="text-align:center;">两者都用</th></tr></thead><tbody><tr><td style="text-align:center;">求速度大小</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">求位移/高度</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">求时间</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">碰撞问题</td><td style="text-align:center;">✅（弹性）</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅（综合）</td></tr><tr><td style="text-align:center;">板块模型</td><td style="text-align:center;">✅（热量）</td><td style="text-align:center;">✅（共速）</td><td style="text-align:center;">✅</td></tr></tbody></table><p><strong>高频考点</strong>：</p><ol><li>动能定理求变力做功</li><li>机械能守恒条件判断</li><li>完全非弹性碰撞（共速）</li><li>人船模型（动量守恒+位移关系）</li><li>能量动量综合（多过程分段）</li></ol><p><strong>与后续知识联系</strong>：</p><ul><li>能量守恒 → 热力学第一定律</li><li>动量守恒 → 原子物理（衰变、核反应）</li><li>功能关系 → 电势能、电功</li></ul><h3 id="faq小节" tabindex="-1">FAQ小节 <a class="header-anchor" href="#faq小节" aria-label="Permalink to &quot;FAQ小节&quot;">​</a></h3><p><strong>Q1：什么时候用动能定理，什么时候用机械能守恒？</strong></p><blockquote><ul><li>能用机械能守恒时优先用（简单，不涉及力的细节）</li><li>有摩擦力或其他非保守力做功时，用动能定理</li><li>动能定理更通用，机械能守恒是特殊情况</li></ul></blockquote><p><strong>Q2：动量守恒和动能定理能同时用吗？</strong></p><blockquote><p>可以，而且经常需要同时用。动量守恒处理矢量关系（方向），动能定理处理标量关系（大小）。碰撞问题中，动量守恒是必须的，弹性碰撞还需动能守恒。</p></blockquote><p><strong>Q3：人船模型为什么位移与质量成反比？</strong></p><blockquote><p>因为水平动量守恒：mv = MV → m(vt) = M(Vt) → mx₁ = Mx₂，所以x₁/x₂ = M/m。质量大的位移小，质量小的位移大。</p></blockquote><p><strong>Q4：弹簧最大压缩量为什么对应共速？</strong></p><blockquote><p>弹簧压缩量最大时，两物体间没有相对运动（如果有相对运动，弹簧还在压缩）。相对速度为0意味着两物体速度相同。</p></blockquote><hr><p><strong>学习建议</strong>：</p><ol><li>先熟练掌握单个模型（动能定理、动量守恒）</li><li>再练习两个模型的结合（碰撞+滑动）</li><li>最后攻克三模型综合（弹簧+碰撞+滑动）</li><li>多画过程图，明确每个阶段用什么工具</li></ol>`,128)])])}const b=s(l,[["render",p]]);export{h as __pageData,b as default};
